use std::thread;
use std::time::Duration;

fn main() {
    // This is an OS Thread. It is expensive to create.
    let handle = thread::spawn(|| {
        println!("I am a distinct execution context managed by the Kernel.");

        // This 'sleep' blocks the entire OS thread.
        thread::sleep(Duration::from_secs(1));
    });

    handle.join().unwrap();
    println!("Main thread finishes.");
}

use std::thread;

fn main() {
    let mut data = vec![1, 2, 3, 4, 5, 6];

    // Modify data in parallel without Arc/Mutex
    thread::scope(|s| {
        let (first, second) = data.split_at_mut(3);

        s.spawn(|| {
            for x in first { *x *= 2; }
            println!("Chunk 1 processed");
        });

        s.spawn(|| {
            for x in second { *x += 10; }
            println!("Chunk 2 processed");
        });
    }); // Blocks here until both threads finish

    println!("Results: {:?}", data);
}

