use std::sync::{Arc, Mutex, Condvar};
use std::thread;

fn main() {
    let pair = Arc::new((Mutex::new(false), Condvar::new()));
    let pair2 = Arc::clone(&pair);

    thread::spawn(move || {
        let (lock, cvar) = &*pair2;
        let mut started = lock.lock().unwrap();
        // Business logic...
        *started = true;
        // Notify the waiting thread
        cvar.notify_one();
    });

    let (lock, cvar) = &*pair;
    let mut started = lock.lock().unwrap();

    // MUST use while loop to handle spurious wakeups
    while !*started {
        println!("Waiting...");
        started = cvar.wait(started).unwrap();
    }

    println!("Worker started!");
}

// Concept code - Manual State Machine
enum MyFuture {
    Init,
    WaitingForTimer { state: i32 },
    Done,
}

impl MyFuture {
    fn poll(&mut self) -> bool {
        match self {
            MyFuture::Init => {
                println!("Start");
                *self = MyFuture::WaitingForTimer { state: 10 };
                false // Pending
            },
            MyFuture::WaitingForTimer { state } => {
                println!("Resumed with state {}", state);
                *self = MyFuture::Done;
                true // Ready
            },
            MyFuture::Done => true,
        }
    }
}

